let raw = $json.output;

// تنظيف markdown
let clean = raw
  .replace(/```json/g, '')
  .replace(/```/g, '')
  .trim();

let parsed;

try {
  // 🔥 الحل السحري
  parsed = eval('(' + clean + ')');
} catch (e) {
  return [
