parameters.jsCode:
let raw = $json.output;

// 🧹 إزالة markdown (```json)
raw = raw.replace(/```json/g, '')
         .replace(/```/g, '')
         .trim();

// 🧠 استخراج JSON فقط (من أول { إلى آخر })
const firstBrace = raw.indexOf('{');
const lastBrace = raw.lastIndexOf('}');

if (firstBrace === -1 || lastBrace === -1) {
  return [{ json: { error: "No JSON found", raw } }];
}

let jsonString = raw.substring(firstBrace, lastBrace + 1);

// 🧪 محاولة التحويل
try {
  const parsed = JSON.parse(jsonString);
  return [{ json: parsed }];
} catch (e) {
  return [{
    json: {
      error: "JSON parse failed",
      message: e.message,
      raw: jsonString
    }
  }];
}

const incoming = $('Edit Fields3').first().json;


let payload = incoming;

if (incoming.query) {
  try {
    payload = JSON.parse(incoming.query);
  } catch (e) {
    payload = {};
  }
}


const answers = payload.answers ?? [];
const user_id = payload.user_id ?? null;
const test_version = payload.test_version ?? "v1";

const scores = { R: 0, I: 0, A: 0, S: 0, E: 0, C: 0 };

for (const a of answers) {
  const d = a.domain;
  const c = Number(a.choice);

  if (scores[d] !== undefined && Number.isFinite(c)) {
    scores[d] += c;
  }
}

const MAX = 28;

const percentages = {};
for (const k of Object.keys(scores)) {
  percentages[k] = Math.round((scores[k] / MAX) * 100);
}

const tieOrder = ["R", "I", "A", "S", "E", "C"];
const sorted = Object.keys(scores).sort((a, b) => {
  if (scores[b] !== scores[a]) return scores[b] - scores[a];
  return tieOrder.indexOf(a) - tieOrder.indexOf(b);
});

const top3_code = sorted.slice(0, 3).join("");

return JSON.stringify({
  user_id,
  test_version,
  top3_code,
  scores,
  percentages,
  result_summary: {
    dominant_traits: top3_code.split(""),
    highest_score: Math.max(...Object.values(scores))
  }
});

