parameters.jsCode:
const text = $input.first().json.output || '';

const clean = text
  .replace(/```json/g, '')
  .replace(/```/g, '')
  .trim();

try {
  return [
    {
      json: JSON.parse(clean)
    }
  ];
} catch (error) {
  return [
    {
      json: {
        error: true,
        raw_output: text,
        cleaned_output: clean,
        message: error.message
      }
    }
  ];
}

function sanitizeText(text) {
  if (!text || typeof text !== 'string') return '';

  let cleaned = text;

  // إخفاء الإيميلات
  cleaned = cleaned.replace(
    /[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/gi,
    '[REDACTED_EMAIL]'
  );

  // إخفاء أرقام الجوال/الهاتف
  cleaned = cleaned.replace(
    /(\+?\d[\d\s\-()]{7,}\d)/g,
    '[REDACTED_PHONE]'
  );

  // إخفاء الروابط
  cleaned = cleaned.replace(
    /https?:\/\/\S+/gi,
    '[REDACTED_LINK]'
  );

  // إخفاء أرقام طويلة محتملة مثل الهوية
  cleaned = cleaned.replace(
    /\b\d{10,}\b/g,
    '[REDACTED_ID]'
  );

  return cleaned;
}

const items = $input.all();

for (const item of items) {
  const body = item.json.body || {};

  item.json = {
    source_type: body.source_type || null,
    user_id: body.user_id || null,
    cv_text: sanitizeText(body.cv_text || ''),
    manual_skill: body.manual_skill || '',
    system_skills: body.system_skills || []
  };
}

return items;

return items.map(item => {
  let output = item.json.output;

  output = output
    .replace(/```json/g, "")
    .replace(/```/g, "")
    .trim();

  const parsed = JSON.parse(output);

  return {
    json: {
      send_email: parsed.send_email,
      to: parsed.to || "",
      subject: parsed.subject || "",
      body: parsed.body || "",
      reason: parsed.reason || ""
    }
  };
});
